5	  describe("quote — base price list and processing fee", () => {
6	    it("empty item list → premium 5 G (only the processing fee)", () => {
7	      expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
8	    });
9	    it("single sword (newcomer, plain) → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
10	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }])).toBe(115);
11	    });
12	    it.todo("single amulet (newcomer, plain) → premium 71 G (60 base + 6 first-insurance + 5 fee)");
13	    it.todo("single staff (newcomer, plain) → premium 93 G (80 base + 8 first-insurance + 5 fee)");
14	    it.todo("single potion (newcomer, plain) → premium 49 G (40 base + 4 first-insurance + 5 fee)");
15	  });
16	
17	  describe("quote — component building block", () => {
18	    it.todo("2 runes (no block) → premium 60 G (50 base + 5 first-insurance + 5 fee)");
19	    it.todo("3 runes (block applies) → premium 71 G (60 base + 6 first-insurance + 5 fee)");
20	    it.todo("4 runes (no block — block requires exactly 3) → premium 115 G (100 base + 10 first-insurance + 5 fee)");
21	    it.todo("7 runes (block requires exactly 3, so all 7 billed individually) → premium 198 G (175 base + 17.5 first-insurance + 5 fee = 197.5 rounded up to 198)");
22	    it.todo("2 runes + 1 moonstone (different types, no block) → premium 88 G (75 base + 7.5 first-insurance + 5 fee = 87.5 rounded up)");
