24	  });
25	
26	  describe("quote — modifier thresholds", () => {
27	    it.todo("loyalty threshold: customer with exactly 2 years, plain sword → premium 95 G (100 base − 20 loyalty + 10 first-insurance + 5 fee)");
28	    it.todo("loyalty just below: customer with 1 year, plain sword → premium 115 G (no loyalty discount)");
29	    it.todo("high-enchantment threshold: sword with exactly enchantment 5 → premium 145 G (100 base + 30 high-enchant + 10 first-insurance + 5 fee)");
30	    it.todo("high-enchantment just below: sword with enchantment 4 → premium 115 G (no high-enchant surcharge)");
31	    it.todo("cursed and high-enchantment (sword enchant 5, cursed) → premium 195 G (100 base + 50 curse + 30 high-enchant + 10 first-insurance + 5 fee)");
32	  });
33	
34	  describe("quote — modifier scope on multi-item policies", () => {
35	    it.todo("cursed sword + plain amulet (newcomer) → premium 231 G (policy base 160 + 50 curse on sword only + 10 first-ins sword + 6 first-ins amulet + 5 fee)");
36	  });
37	
38	  describe("quote — integration examples", () => {
39	    it.todo("newcomer with a cursed sword (steel, enchant 3), 0 years, first contract → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
40	    it.todo("long-standing customer's second contract: cursed sword (enchant 7), 3 years, second quote → premium 160 G (100 + 50 + 30 − 20 + 10 − 15 + 5)");
41	  });
42	
43	  describe("claim — standard reimbursement", () => {
44	    it.todo("regular sword (steel, enchant 3), damage 500 G → payout 400 G (full minus 100 deductible)");
45	    it.todo("rune (no enchant/material), damage 200 G → payout 100 G (full minus 100 deductible)");
46	  });
47	
48	  describe("claim — enchantment and dragon-material clauses", () => {
49	    it.todo("dragon sword enchant exactly 8, damage 1000 G → payout 400 G (50%% rule wins, then deductible: 500 − 100)");
50	    it.todo("dragon sword enchant 9, damage 1000 G → payout 400 G (both clauses; 50%% wins, then deductible)");
51	    it.todo("dragon sword enchant 5, damage 800 G → payout 700 G (only dragon clause: full reimbursement, then deductible)");
52	    it.todo("steel sword enchant 9, damage 1000 G → payout 400 G (only high-enchant clause: 50%% first, then deductible)");
53	  });
54	
55	  describe("claim — deductible per damage event", () => {
56	    it.todo("dragon attack damages sword (500 G) + amulet (300 G) → payout 600 G (deductible applies once per damaged item)");
57	    it.todo("two-sword policy, dragon attack with two sword damage entries (500 + 400) → payout 700 G (each entry deducted: 400 + 300)");
58	  });
59	
60	  describe("claim — insurance sum and cap", () => {
61	    it.todo("policy of sword + amulet → insurance sum 1600 G, cap 3200 G");
62	    it.todo("policy with cursed sword (premium 165 G after modifiers) → cap still 2000 G (based on unmodified insurance value)");
63	    it.todo("policy of sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only), cap 3500 G");
64	    it.todo("cap exhaustion: sword policy (cap 2000), claim 1500 → payout 1400, remainingCap 600; claim 1500 → payout 600, remainingCap 0");
65	  });
66	
67	  describe("rounding in MHPCO's favor", () => {
68	    it.todo("premium 197.5 G rounds UP → final premium 198 G");
69	    it.todo("payout 350.5 G rounds DOWN → final payout 350 G (sword enchant 8, damage 901 → half=450.5 − 100 = 350.5)");
70	  });
71	
72	  describe("CLI — JSON in/out", () => {
73	    it.todo("CLI: simple quote step → stdout contains {results: [{premium: ...}]} matching schema");
74	    it.todo("CLI: scenario with quote then claim referencing policy index 0 → stdout has both results in order");
75	    it.todo("CLI: two quote steps for same customer → second quote applies follow-up contract discount (long-standing scenario E32 yields 160 G)");
76	  });
77	
78	  describe("CLI — error handling (exit non-zero, stderr)", () => {
79	    it.todo("CLI: quote includes unknown item type (e.g. broomstick) → exits non-zero, error on stderr, no `results` on stdout");
80	    it.todo("CLI: claim references an item not in the policy (e.g. amulet damaged when only a sword insured) → exits non-zero, error on stderr");
81	    it.todo("CLI: claim damage entry with negative amount → exits non-zero, error on stderr");
82	    it.todo("CLI: claim contains more damage entries of a type than the policy covers (two sword damages, one sword insured) → exits non-zero, error on stderr");
